261	func (h *WorkOrderHandler) GetWorkOrder(c echo.Context) error {
262		id := c.Param("id")
263		if id == "" {
264			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
265				Error: "Work order ID is required",
266				Code:  http.StatusBadRequest,
267			})
268		}
269	
270		wo, err := h.repo.GetWorkOrderByID(id)
271		if err != nil || wo == nil {
272			return c.JSON(http.StatusNotFound, models.ErrorResponse{
273				Error:   "Work order not found",
274				Code:    http.StatusNotFound,
275				Details: "No work order found with the given ID",
276			})
277		}
278	
279		userID := middleware.GetUserID(c)
280		role := middleware.GetUserRole(c)
281		if !canViewWorkOrder(userID, role, wo.SubmittedBy, wo.AssignedTo) {
282			return c.JSON(http.StatusForbidden, models.ErrorResponse{
283				Error:   "Access denied",
284				Code:    http.StatusForbidden,
285				Details: "You are not authorized to view this work order",
286			})
287		}
288	
289		photos, err := h.repo.GetWorkOrderPhotos(id)
290		if err != nil {
291			logrus.WithError(err).Error("Failed to get work order photos")
292			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
293				Error: "Failed to retrieve work order photos",
294				Code:  http.StatusInternalServerError,
295			})
296		}
297		if photos == nil {
298			photos = []models.ManagedFile{}
299		}
300	
301		return c.JSON(http.StatusOK, map[string]interface{}{
302			"work_order": wo,
303			"photos":     photos,
304		})
305	}
