409	// CloseWorkOrder closes a work order with parts/labor cost.
410	func (h *WorkOrderHandler) CloseWorkOrder(c echo.Context) error {
411		id := c.Param("id")
412		if id == "" {
413			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
414				Error: "Work order ID is required",
415				Code:  http.StatusBadRequest,
416			})
417		}
418	
419		wo, err := h.repo.GetWorkOrderByID(id)
420		if err != nil || wo == nil {
421			return c.JSON(http.StatusNotFound, models.ErrorResponse{
422				Error:   "Work order not found",
423				Code:    http.StatusNotFound,
424				Details: "No work order found with the given ID",
425			})
426		}
427	
428		if wo.Status == "completed" || wo.Status == "closed" || wo.Status == "cancelled" {
429			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
430				Error:   "Work order already closed or cancelled",
431				Code:    http.StatusBadRequest,
432				Details: "This work order has already been completed, closed, or cancelled",
433			})
434		}
435	
436		var req models.CloseWorkOrderRequest
437		if err := c.Bind(&req); err != nil {
438			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
439				Error: "Invalid request body",
440				Code:  http.StatusBadRequest,
441			})
442		}
443	
444		now := time.Now()
445		wo.PartsCost = req.PartsCost
446		wo.LaborCost = req.LaborCost
447		wo.Status = "completed"
448		wo.ClosedAt = &now
449	
450		if err := h.repo.UpdateWorkOrder(wo); err != nil {
451			logrus.WithError(err).Error("Failed to close work order")
452			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
453				Error: "Failed to close work order",
454				Code:  http.StatusInternalServerError,
455			})
456		}
