262	      const members: Array<{ name: string; expires_at: string }> = payload.data ?? [];
263	      const now = Date.now();
264	      for (const m of members) {
265	        const expiresMs = new Date(m.expires_at).getTime();
266	        const daysLeft = (expiresMs - now) / (1000 * 60 * 60 * 24);
267	        if (daysLeft < 0) continue; // already expired — skip
268	        if (daysLeft <= 1) {
269	          fireNotification(
270	            'URGENT: Membership Expiring Today',
271	            `URGENT: Member ${m.name} expires today!`,
272	            opts.onOpen,
273	          );
274	        } else if (daysLeft <= 7) {
275	          const n = Math.ceil(daysLeft);
276	          fireNotification(
277	            'Membership Expiry Warning',
278	            `Member ${m.name} membership expires in ${n} days`,
279	            opts.onOpen,
280	          );
281	        } else if (daysLeft <= 14) {
282	          const n = Math.ceil(daysLeft);
283	          fireNotification(
284	            'Membership Expiry Reminder',
285	            `Reminder: Member ${m.name} membership expires in ${n} days`,
286	            opts.onOpen,
287	          );
288	        }
289	      }
290	    }
291	
292	    // Check low-stock SKUs.
