200	// copyDir recursively copies all files from src to dst, preserving permissions.
201	func copyDir(src, dst string) error {
202		return filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
203			if err != nil {
204				return err
205			}
206			rel, relErr := filepath.Rel(src, path)
207			if relErr != nil {
208				return relErr
209			}
210			target := filepath.Join(dst, rel)
211			if info.IsDir() {
212				return os.MkdirAll(target, info.Mode())
213			}
214			return copyFile(path, target, info.Mode())
215		})
216	}
217	
218	// copyFile copies a single file from src to dst, creating parent directories as needed.
219	func copyFile(src, dst string, mode os.FileMode) error {
220		in, err := os.Open(src)
221		if err != nil {
222			return err
223		}
224		defer in.Close()
225		if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
226			return err
227		}
228		out, err := os.OpenFile(dst, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, mode)
229		if err != nil {
230			return err
231		}
232		defer out.Close()
233		_, err = io.Copy(out, in)
234		return err
235	}
